=You are an expert assessment designer.
Generate structured exam questions based strictly on the provided material.
Return ONLY valid JSON with this format:

{
“mcq”: [
{
“question”: “”,
“options”: {
“A”: “”,
“B”: “”,
“C”: “”,
“D”: “”
},
“answer”: “A”,
“difficulty”: “”
}
],
“essay”: [
{
“question”: “”,
“expected_points”: “”,
“difficulty”: “”
}
]
}

Rules:
	•	Questions must strictly follow the requested difficulty level.
	•	Avoid generic or vague questions.
	•	Do not include explanations outside JSON.

⸻

USER PROMPT dynamic:

Material:
{{ $json.cleaned_text }}
Generate:
	•	{{ $('Webhook').item.json.body.mcq_count }} multiple choice questions
	•	{{ $('Webhook').item.json.body.essay_count }} essay questions
Difficulty: {{ $('Webhook').item.json.body.difficulty }}
Language: {{ $('Webhook').item.json.body.language }}

parameters.jsCode:
let raw = $input.first().json.output[0].content[0].text
//let raw = $json.choices?.[0]?.message?.content || "";

// Hapus markdown code block jika ada
raw = raw.replace(/```json/g, "")
         .replace(/```/g, "")
         .trim();

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (error) {
  throw new Error("Invalid JSON from OpenAI. Please check prompt structure.");
}

return [
  {
    json: parsed
  }
];

// Ambil text hasil extract PDF
let text = $json.text || $json.data || "";

// Pastikan string
text = String(text);

// Hilangkan karakter aneh non-printable
text = text.replace(/[^\x20-\x7E\n\r]/g, "");

// Hilangkan newline berlebihan
text = text.replace(/\n\s*\n/g, "\n");

// Hilangkan spasi ganda
text = text.replace(/\s+/g, " ");

// Trim
text = text.trim();

// Batasi panjang (misal 15.000 karakter untuk safety)
const MAX_LENGTH = 15000;

if (text.length > MAX_LENGTH) {
  text = text.substring(0, MAX_LENGTH);
}

return [
  {
    json: {
      cleaned_text: text
    }
  }
];

const text = $input.first().json.cleaned_text;

const estimatedTokens = Math.ceil(text.length / 4);

const MAX_TOKENS = 8000; // batas aman V1

if (estimatedTokens > MAX_TOKENS) {
  return [
    {
      json: {
        error: true,
        message: "Document too long. Please upload a shorter PDF (recommended max 15–20 pages).",
        estimated_tokens: estimatedTokens
      }
    }
  ];
}

return [
  {
    json: {
      error : false,
      cleaned_text: text,
      estimated_tokens: estimatedTokens
    }
  }
];

const mcq = $input.first().json.mcq || [];
const essay = $input.first().json.essay || [];

let examText = "";
let answerKey = "";

examText += "<h1>Exam Paper</h1><hr>";

/* =======================
   MULTIPLE CHOICE
======================= */

if (mcq.length > 0) {
  examText += "<h2>Multiple Choice Questions</h2>";

  mcq.forEach((q, index) => {
    examText += `<p><strong>${index + 1}. ${q.question}</strong></p>`;
    examText += `<p>A. ${q.options?.A || ""}</p>`;
    examText += `<p>B. ${q.options?.B || ""}</p>`;
    examText += `<p>C. ${q.options?.C || ""}</p>`;
    examText += `<p>D. ${q.options?.D || ""}</p>`;
  });

  answerKey += "<h2>Answer Key - MCQ</h2>";
  mcq.forEach((q, index) => {
    answerKey += `<p>${index + 1}. ${q.answer}</p>`;
  });
}

/* =======================
   ESSAY
======================= */

if (essay.length > 0) {
  examText += "<hr><h2>Essay Questions</h2>";

  essay.forEach((q, index) => {
    examText += `<p><strong>${index + 1}. ${q.question}</strong></p>`;
  });

  answerKey += "<hr><h2>Answer Guide - Essay</h2>";
  essay.forEach((q, index) => {
    answerKey += `<p><strong>${index + 1}.</strong> ${q.expected_points || ""}</p>`;
  });
}

return [
  {
    json: {
      exam_html: examText,
      answer_key_html: answerKey
    }
  }
];

