parameters.jsCode:
const errors = [];

const mcq = $input.first().json.body.mcq_count
const essay = $input.first().json.body.essay_count;
const difficulty = $input.first().json.body.difficulty;
const language = $input.first().json.body.language;

let fileSize = $input.first().binary.data.fileSize
let size = String(fileSize).toLowerCase();
let fileSizeInBytes = parseInt(
  size.includes('mb')
    ? parseFloat(size) * 1024 * 1024
    : size.includes('kb')
      ? parseFloat(size) * 1024
      : parseFloat(size)
);

if(fileSizeInBytes >=5242880){
  errors.push("Files cannot be more than 5MB");
}

// Check required fields
if (!mcq) {
  errors.push("mcq_count is required");
}

if (!essay) {
  errors.push("essay_count is required");
}

if (!difficulty) {
  errors.push("difficulty is required (easy | medium | hard)");
}

if (!language) {
  errors.push("language is required");
}

// Validate numeric
if (mcq && isNaN(mcq)) {
  errors.push("mcq_count must be a number");
}

if (essay && isNaN(essay)) {
  errors.push("essay_count must be a number");
}

// Validate difficulty value
const allowedDifficulty = ["easy", "medium", "hard"];
if (difficulty && !allowedDifficulty.includes(difficulty)) {
  errors.push("difficulty must be: easy, medium, or hard");
}

if (mcq && mcq > 50) {
  errors.push("mcq_count maximum is 50");
}

if (essay && essay > 50) {
  errors.push("essay_count maximum is 20");
}

return [{
  json: {
    isValid: errors.length === 0,
    errors: errors,
    mcq_count: mcq,
    essay_count: essay,
    difficulty: difficulty,
    language: language,
    data : $input.first().binary.data
  }
}];
